using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // --- AddItem ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleSkus_SumsCorrectly()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 2, 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [DataTestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 1.00m));
    }

    [DataTestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-1", quantity, 1.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-1", 1, -1.00m));
    }

    // --- RemoveItem ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 5.00m);

        _cart.RemoveItem("A");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(() => _cart.RemoveItem("MISSING"));
    }

    [DataTestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));
    }

    // --- CalculateTotal ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingAllItems_ReturnsZero()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon ---

    [DataTestMethod]
    [DataRow("SAVE10", 10)]
    [DataRow("SAVE20", 20)]
    [DataRow("HALF", 50)]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, int expectedPercent)
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.ApplyCoupon(code);

        var expected = 100.00m - (100.00m * expectedPercent / 100m);
        Assert.AreEqual(expected, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_Works()
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));
    }

    [DataTestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmpty_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedBeforeAddingItems_StillDiscounts()
    {
        _cart.ApplyCoupon("SAVE10");
        _cart.AddItem("A", 2, 50.00m);

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }
}

